#!/bin/bash
set -euo pipefail
NAME=${1:?Usage: create-ingress.sh <name> <host> <service> <port>}
HOST=${2:?Usage: create-ingress.sh <name> <host> <service> <port>}
SERVICE=${3:?Usage: create-ingress.sh <name> <host> <service> <port>}
PORT=${4:?Usage: create-ingress.sh <name> <host> <service> <port>}
NS=${KUBE_NAMESPACE:-default}

kubectl create ingress "$NAME" \
  --rule="${HOST}/*=${SERVICE}:${PORT}" \
  --class=nginx \
  -n "$NS" \
  --dry-run=client -o yaml | kubectl apply -f -

echo "Ingress $NAME created/updated:"
kubectl get ingress "$NAME" -n "$NS"
